example.code:
let s1 = String::from("hello");
let s3 = s1;          // s1 moved into s3
// println!("{}", s1); // compile error: s1 moved

let x = 5;
let y = x;            // copied — x is still valid
println!("{} {}", x, y);

fn calculate_length(s: &String) -> usize { s.len() }

let mut s = String::from("hello");
let len1 = calculate_length(&s);
let len2 = calculate_length(&s);   // multiple immutable borrows OK
// mutable borrow is fine after last immutable borrow use
let r = &mut s;
r.push_str(" world");

let r1 = &s;
let r2 = &s;
let r3 = &mut s; // ERROR: cannot borrow as mutable while immutable borrows exist
println!("{} {}", r1, r2);

// Compiler can infer: output lifetime = input lifetime
fn first_word(s: &str) -> &str {
    s.split_whitespace().next().unwrap_or("")
}

// Explicit needed: two inputs, compiler can't guess which to tie output to
fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

// Lifetime in struct: struct cannot outlive the slice it holds
struct Excerpt<'a> {
    part: &'a str,
}

enum List {
    Cons(i32, Box<List>),
    Nil,
}
// Without Box, List has infinite size — compiler rejects it.

use std::rc::Rc;
let data = Rc::new(vec![1, 2, 3]);
let data2 = Rc::clone(&data); // increments refcount
println!("count: {}", Rc::strong_count(&data)); // 2

use std::sync::{Arc, Mutex};
use std::thread;

let counter = Arc::new(Mutex::new(0));
let handles: Vec<_> = (0..10).map(|_| {
    let c = Arc::clone(&counter);
    thread::spawn(move || { *c.lock().unwrap() += 1; })
}).collect();
for h in handles { h.join().unwrap(); }
println!("{}", *counter.lock().unwrap()); // 10

use std::borrow::Cow;
fn normalize(input: &str) -> Cow<str> {
    if input.contains("  ") {
        Cow::Owned(input.replace("  ", " "))
    } else {
        Cow::Borrowed(input)
    }
}
